import pytest

def test_non_admin_export_csv_returns_403(
    employee_token, # <fixture> returns valid bearer token for role:employee
    api_client,     # <fixture> returns configured requests.Session
):
    resp = api_client.get(
        "/api/employees/export.csv",
        headers={"Authorization": f"Bearer {employee_token}"},
    )
    assert resp.status_code == 403
    body = resp.json() if resp.headers.get("Content-Type", "").startswith("application/json") else {}
    assert body.get("error") or body.get("message") or resp.text, \
        "403 response should carry an error description"
